import { TankClass } from '../types';

export class SoundEngine {
  ctx: AudioContext;
  masterGain: GainNode;
  noiseBuffer: AudioBuffer | null = null;
  volume: number = 0.15;
  private enabled: boolean = false;

  // Throttle tracking to prevent audio clipping during high fire rates
  private lastPlayed: Record<string, number> = {};

  constructor() {
    // @ts-ignore
    const AudioContextClass = window.AudioContext || window.webkitAudioContext;
    this.ctx = new AudioContextClass();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = this.volume;

    // Add a master limiter to prevent clipping when many sounds play simultaneously
    const limiter = this.ctx.createDynamicsCompressor();
    limiter.threshold.setValueAtTime(-1, this.ctx.currentTime);
    limiter.knee.setValueAtTime(40, this.ctx.currentTime);
    limiter.ratio.setValueAtTime(12, this.ctx.currentTime);
    limiter.attack.setValueAtTime(0, this.ctx.currentTime);
    limiter.release.setValueAtTime(0.25, this.ctx.currentTime);

    this.masterGain.connect(limiter);
    limiter.connect(this.ctx.destination);

    this.noiseBuffer = this.createNoiseBuffer();
  }

  private throttle(key: string, cooldownMs: number): boolean {
    const now = Date.now();
    if (this.lastPlayed[key] && now - this.lastPlayed[key] < cooldownMs) {
      return false;
    }
    this.lastPlayed[key] = now;
    return true;
  }

  async resume() {
    if (this.ctx.state === 'suspended') {
      await this.ctx.resume();
    }
  }

  enable() {
    this.enabled = true;
    this.resume();
  }

  setVolume(value: number) {
    this.volume = Math.max(0, Math.min(1, value));
    if (this.masterGain) {
      this.masterGain.gain.setTargetAtTime(this.volume, this.ctx.currentTime, 0.05);
    }
  }

  // Small helper: random factor around 1.0
  private jitter(center = 1, amount = 0.1) {
    return center * (1 - amount + Math.random() * amount * 2);
  }

  // Small helper: create a panned gain node
  private createPannedGain(panRange = 0.4): { gain: GainNode; panNode: StereoPannerNode } {
    const gain = this.ctx.createGain();
    const panNode = this.ctx.createStereoPanner();
    panNode.pan.value = (Math.random() - 0.5) * panRange;
    gain.connect(panNode);
    panNode.connect(this.masterGain);
    return { gain, panNode };
  }

  playRoar() {
    if (!this.enabled) return;
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    const duration = 2.2; 

    // --- LAYER 1: THE SUB-SLAM (Chest punch) ---
    {
        const osc = this.ctx.createOscillator();
        const { gain: g } = this.createPannedGain(0.1);
        osc.type = 'sine';
        osc.frequency.setValueAtTime(50, t);
        osc.frequency.exponentialRampToValueAtTime(15, t + 0.6);

        g.gain.setValueAtTime(0, t);
        g.gain.linearRampToValueAtTime(1.0, t + 0.02);
        g.gain.exponentialRampToValueAtTime(0.001, t + 0.6);

        osc.connect(g);
        osc.start(t);
        osc.stop(t + 0.6);
    }

    // --- LAYER 2: THE "GRIT" (Mechanical Rattle) ---
    {
        const osc1 = this.ctx.createOscillator();
        const osc2 = this.ctx.createOscillator();
        const { gain: g } = this.createPannedGain(0.3);
        const lp = this.ctx.createBiquadFilter();

        osc1.type = 'sawtooth';
        osc2.type = 'sawtooth';
        osc1.frequency.setValueAtTime(90, t);
        osc2.frequency.setValueAtTime(88, t);
        osc1.frequency.exponentialRampToValueAtTime(25, t + duration);
        osc2.frequency.exponentialRampToValueAtTime(24, t + duration);

        lp.type = 'lowpass';
        lp.frequency.setValueAtTime(1200, t);
        lp.frequency.exponentialRampToValueAtTime(80, t + duration);

        g.gain.setValueAtTime(0, t);
        g.gain.linearRampToValueAtTime(0.6, t + 0.05);
        g.gain.exponentialRampToValueAtTime(0.001, t + duration);

        osc1.connect(lp);
        osc2.connect(lp);
        lp.connect(g);
        osc1.start(t);
        osc2.start(t);
        osc1.stop(t + duration);
        osc2.stop(t + duration);
    }

    // --- LAYER 3: THE "NULL" EXHALE (Heavy Steam) ---
    if (this.noiseBuffer) {
        const src = this.ctx.createBufferSource();
        src.buffer = this.noiseBuffer;
        const { gain: g } = this.createPannedGain(0.6);
        const bp = this.ctx.createBiquadFilter();

        bp.type = 'bandpass';
        bp.frequency.setValueAtTime(3000, t);
        bp.frequency.exponentialRampToValueAtTime(100, t + duration);
        bp.Q.setValueAtTime(0.5, t);
        bp.Q.linearRampToValueAtTime(4.0, t + duration);

        g.gain.setValueAtTime(0, t);
        g.gain.linearRampToValueAtTime(0.4, t + 0.05);
        g.gain.exponentialRampToValueAtTime(0.001, t + duration);

        src.connect(bp);
        bp.connect(g);
        src.start(t);
        src.stop(t + duration);
    }
  }

  playShoot(type: TankClass = TankClass.BASIC) {
    if (!this.enabled) return;
    this.resume();
    if (this.volume <= 0.001) return;

    const minCooldown = (type === TankClass.STREAMLINER || type === TankClass.GUNNER) ? 22 : 38;
    if (!this.throttle(`shoot-${type}`, minCooldown)) return;

    const t = this.ctx.currentTime;
    const pitchVariance = 0.9 + Math.random() * 0.2;

    let baseFreq = 180;
    let sweepDepth = 0.15;
    let duration = 0.2;
    let amplitude = 0.4;
    let waveType: OscillatorType = 'triangle';
    let attackTime = 0.008;
    let noiseIntensity = 0.6;
    let noiseDecay = 0.08;
    let metalResonance = 0; // Simulated metallic ringing
    let addSub = true;

    // --- Tank-Specific Heavy Profiles ---
    switch (type) {
      case TankClass.SNIPER:
      case TankClass.ASSASSIN:
      case TankClass.RANGER:
      case TankClass.STALKER:
        baseFreq = 440; sweepDepth = 0.02; duration = 0.45; amplitude = 0.55; waveType = 'sawtooth';
        noiseIntensity = 1.0; noiseDecay = 0.15; metalResonance = 1500;
        break;
      case TankClass.MACHINE_GUN:
      case TankClass.SPRAYER:
        baseFreq = 140; sweepDepth = 0.3; duration = 0.12; amplitude = 0.3; waveType = 'square';
        noiseIntensity = 0.5; noiseDecay = 0.04; metalResonance = 400;
        break;
      case TankClass.STREAMLINER:
      case TankClass.GUNNER:
      case TankClass.AUTO_GUNNER:
        baseFreq = 280; sweepDepth = 0.5; duration = 0.08; amplitude = 0.2; waveType = 'triangle';
        noiseIntensity = 0.3; noiseDecay = 0.03; addSub = false;
        break;
      case TankClass.DESTROYER:
      case TankClass.HYBRID:
      case TankClass.ANNIHILATOR:
        baseFreq = 75; sweepDepth = 0.05; duration = 0.8; amplitude = 0.8; waveType = 'sine';
        attackTime = 0.02; noiseIntensity = 1.5; noiseDecay = 0.5; metalResonance = 200;
        break;
      case TankClass.HUNTER:
      case TankClass.X_HUNTER:
        baseFreq = 380; sweepDepth = 0.2; duration = 0.3; amplitude = 0.45; waveType = 'sawtooth';
        noiseIntensity = 0.7; noiseDecay = 0.1; metalResonance = 800;
        break;
      default: // BASIC / TWIN
        baseFreq = 200; sweepDepth = 0.1; duration = 0.2; amplitude = 0.4; waveType = 'triangle';
        metalResonance = 600;
        break;
    }

    const finalBaseFreq = baseFreq * pitchVariance;
    const ampRand = amplitude * this.jitter(1, 0.1);
    const durationRand = duration * this.jitter(1, 0.08);

    // --- LAYER 1: MECHANICAL CLICK (Firing Pin) ---
    {
      const pinOsc = this.ctx.createOscillator();
      const { gain: pinG } = this.createPannedGain(0.2);
      pinOsc.type = 'square';
      pinOsc.frequency.setValueAtTime(finalBaseFreq * 4, t);
      pinG.gain.setValueAtTime(0, t);
      pinG.gain.linearRampToValueAtTime(ampRand * 0.4, t + 0.001);
      pinG.gain.linearRampToValueAtTime(0, t + 0.005);
      pinOsc.connect(pinG);
      pinOsc.start(t);
      pinOsc.stop(t + 0.01);
    }

    // --- LAYER 2: BORE BLAST (The main tone) ---
    {
      const bodyOsc = this.ctx.createOscillator();
      const { gain: bodyGain } = this.createPannedGain(0.35);
      bodyOsc.type = waveType;
      bodyOsc.frequency.setValueAtTime(finalBaseFreq, t);
      bodyOsc.frequency.exponentialRampToValueAtTime(
        Math.max(20, finalBaseFreq * sweepDepth),
        t + durationRand
      );

      bodyGain.gain.setValueAtTime(0, t);
      bodyGain.gain.linearRampToValueAtTime(ampRand, t + attackTime);
      bodyGain.gain.exponentialRampToValueAtTime(0.001, t + durationRand);

      bodyOsc.connect(bodyGain);
      bodyOsc.start(t);
      bodyOsc.stop(t + durationRand + 0.1);
    }

    // --- LAYER 3: MUZZLE SMOKE & METAL RING ---
    if (this.noiseBuffer) {
      const noiseSrc = this.ctx.createBufferSource();
      noiseSrc.buffer = this.noiseBuffer;
      const { gain: noiseGain } = this.createPannedGain(0.4);

      const bp = this.ctx.createBiquadFilter();
      bp.type = 'bandpass';
      bp.frequency.setValueAtTime(finalBaseFreq * 2, t);
      bp.Q.value = metalResonance > 0 ? 8 : 1;

      if (metalResonance > 0) {
          bp.frequency.exponentialRampToValueAtTime(metalResonance, t + 0.1);
      }

      noiseGain.gain.setValueAtTime(0, t);
      noiseGain.gain.linearRampToValueAtTime(ampRand * noiseIntensity, t + 0.005);
      noiseGain.gain.exponentialRampToValueAtTime(0.001, t + noiseDecay);

      noiseSrc.connect(bp);
      bp.connect(noiseGain);
      noiseSrc.start(t);
      noiseSrc.stop(t + noiseDecay + 0.1);
    }

    // --- LAYER 4: SUB-THUMP ---
    if (addSub) {
      const sub = this.ctx.createOscillator();
      const { gain: subG } = this.createPannedGain(0.1);
      sub.type = 'sine';
      sub.frequency.setValueAtTime(45 * pitchVariance, t);
      sub.frequency.exponentialRampToValueAtTime(20, t + 0.1);

      subG.gain.setValueAtTime(0, t);
      subG.gain.linearRampToValueAtTime(ampRand * 0.5, t + 0.01);
      subG.gain.exponentialRampToValueAtTime(0.001, t + 0.12);

      sub.connect(subG);
      sub.start(t);
      sub.stop(t + 0.15);
    }
  }

  playHit() {
    if (!this.enabled) return;
    this.resume();
    if (this.volume <= 0.001) return;

    if (!this.throttle('hit', 70)) return;

    const t = this.ctx.currentTime;
    const pitch = 0.7 + Math.random() * 0.5;

    const osc = this.ctx.createOscillator();
    const { gain } = this.createPannedGain(0.2);
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(140 * pitch, t);
    osc.frequency.linearRampToValueAtTime(60, t + 0.06);

    const bp = this.ctx.createBiquadFilter();
    bp.type = 'bandpass';
    bp.frequency.value = 800 * pitch;
    bp.Q.value = 5;

    const peak = 0.2 * this.jitter(1, 0.1);

    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(peak, t + 0.002);
    gain.gain.linearRampToValueAtTime(0, t + 0.06);

    osc.connect(bp);
    bp.connect(gain);
    osc.start(t);
    osc.stop(t + 0.08);
  }

  playExplosion(isLarge: boolean = false) {
    if (!this.enabled) return;
    this.resume();
    if (this.volume <= 0.001) return;
    if (!this.noiseBuffer) return;

    if (!this.throttle(isLarge ? 'explosion-large' : 'explosion-small', 200)) return;

    const t = this.ctx.currentTime;
    const duration = (isLarge ? 1.4 : 0.6) * this.jitter(1, 0.1);
    const vol = (isLarge ? 0.7 : 0.4) * this.jitter(1, 0.1);

    // Main heavy noise body
    const src = this.ctx.createBufferSource();
    src.buffer = this.noiseBuffer;

    const lp = this.ctx.createBiquadFilter();
    lp.type = 'lowpass';
    lp.frequency.setValueAtTime(isLarge ? 250 : 600, t);
    lp.frequency.exponentialRampToValueAtTime(15, t + duration);

    const { gain } = this.createPannedGain(0.4);
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(vol, t + 0.02);
    gain.gain.exponentialRampToValueAtTime(0.001, t + duration);

    src.connect(lp);
    lp.connect(gain);
    src.start(t);
    src.stop(t + duration + 0.2);

    // Debris layer (High-frequency scatter)
    const debris = this.ctx.createBufferSource();
    debris.buffer = this.noiseBuffer;
    const { gain: debrisG } = this.createPannedGain(0.5);
    const hp = this.ctx.createBiquadFilter();
    hp.type = 'highpass';
    hp.frequency.setValueAtTime(2000, t);

    debrisG.gain.setValueAtTime(0, t);
    debrisG.gain.linearRampToValueAtTime(vol * 0.4, t + 0.05);
    debrisG.gain.exponentialRampToValueAtTime(0.001, t + (duration * 0.5));

    debris.connect(hp);
    hp.connect(debrisG);
    debris.start(t);
    debris.stop(t + duration);

    // Shockwave Rumble
    if (isLarge) {
      const rumble = this.ctx.createOscillator();
      const { gain: rumbleG } = this.createPannedGain(0.1);
      rumble.type = 'sine';
      rumble.frequency.setValueAtTime(60, t);
      rumble.frequency.exponentialRampToValueAtTime(10, t + duration);

      rumbleG.gain.setValueAtTime(0, t);
      rumbleG.gain.linearRampToValueAtTime(0.4, t + 0.08);
      rumbleG.gain.exponentialRampToValueAtTime(0.001, t + duration);

      rumble.connect(rumbleG);
      rumble.start(t);
      rumble.stop(t + duration + 0.1);
    }
  }

  playLevelUp() {
    if (!this.enabled) return;
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    const notes = [523.25, 659.25, 783.99, 1046.50];

    notes.forEach((freq, i) => {
      const osc = this.ctx.createOscillator();
      const { gain } = this.createPannedGain(0.2);
      const start = t + i * 0.06;

      osc.type = 'sine';
      osc.frequency.setValueAtTime(freq, start);

      const peak = 0.15 * this.jitter(1, 0.05);

      gain.gain.setValueAtTime(0, start);
      gain.gain.linearRampToValueAtTime(peak, start + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, start + 0.5);

      osc.connect(gain);
      osc.start(start);
      osc.stop(start + 0.6);
    });
  }

  playUIHover() {
    if (!this.enabled) return;
    this.resume();
    if (this.volume <= 0.001) return;
    if (!this.throttle('ui-hover', 45)) return;

    const t = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const { gain } = this.createPannedGain(0.1);
    osc.type = 'sine';
    osc.frequency.setValueAtTime(1100, t);
    osc.frequency.exponentialRampToValueAtTime(1400, t + 0.03);
    gain.gain.setValueAtTime(0.02, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.03);
    osc.connect(gain);
    osc.start(t);
    osc.stop(t + 0.04);
  }

  playUIClick() {
    if (!this.enabled) return;
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const { gain } = this.createPannedGain(0.15);
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(330, t);
    osc.frequency.exponentialRampToValueAtTime(80, t + 0.06);
    gain.gain.setValueAtTime(0.2, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.06);
    osc.connect(gain);
    osc.start(t);
    osc.stop(t + 0.08);
  }

  playStatUpgrade() {
    if (!this.enabled) return;
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    [1046.50, 1318.51].forEach((f, i) => {
      const o = this.ctx.createOscillator();
      const { gain } = this.createPannedGain(0.15);
      const s = t + i * 0.04;
      o.type = 'sine';
      o.frequency.setValueAtTime(f, s);
      gain.gain.setValueAtTime(0, s);
      gain.gain.linearRampToValueAtTime(0.1, s + 0.01);
      gain.gain.exponentialRampToValueAtTime(0.001, s + 0.15);
      o.connect(gain);
      o.start(s);
      o.stop(s + 0.2);
    });
  }

  playClassUpgrade() {
    if (!this.enabled) return;
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    const notes = [440, 554.37, 659.25];
    notes.forEach((f) => {
      const o = this.ctx.createOscillator();
      const { gain } = this.createPannedGain(0.2);
      o.type = 'triangle';
      o.frequency.setValueAtTime(f, t);
      gain.gain.setValueAtTime(0, t);
      gain.gain.linearRampToValueAtTime(0.12, t + 0.04);
      gain.gain.exponentialRampToValueAtTime(0.001, t + 0.7);
      o.connect(gain);
      o.start(t);
      o.stop(t + 0.8);
    });
  }

  private createNoiseBuffer() {
    const bufferSize = this.ctx.sampleRate * 2.5;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }
    return buffer;
  }
}
